INSERT INTO ai_automation.knowledge_base (kb_id,category,subcategory,question,answer,related_cpt_codes,related_icd_codes,usage_count,helpfulness_score,active) VALUES
('KB001','Benefits','Deductible','What is a deductible?','A deductible is the amount you pay for covered health care services before your insurance plan starts to pay.',NULL,NULL,150,4.56,TRUE),
('KB002','Benefits','Copay','What is a copay?','A copay is a fixed amount you pay for a health care service, usually at the time of service.',NULL,NULL,397,4.94,TRUE),
('KB003','Benefits','OOP Max','What is an out-of-pocket maximum?','The most you have to pay for covered services in a plan year. After you spend this amount, the plan pays 100%.',NULL,NULL,206,4.13,TRUE),
('KB004','Claims','Status','How do I check my claim status?','You can check your claim status online, by phone, or through our mobile app.',NULL,NULL,491,4.88,TRUE),
('KB005','Claims','Denial','Why was my claim denied?','Claims can be denied for various reasons including lack of coverage, missing information, or medical necessity.',NULL,NULL,208,4.24,TRUE),
('KB006','Enrollment','Coverage','When does my coverage start?','Coverage typically starts on the first day of the month following your enrollment date.',NULL,NULL,11,4.98,TRUE),
('KB007','Enrollment','Dependents','How do I add a dependent?','You can add dependents during open enrollment or within 30 days of a qualifying life event.',NULL,NULL,242,3.31,TRUE),
('KB008','Billing','Premium','How do I pay my premium?','You can pay your premium online, by mail, or set up automatic payments through our member portal.',NULL,NULL,327,3.24,TRUE),
('KB009','Billing','Overpayment','What if I overpaid?','Overpayments will be refunded within 30 days or applied to your next billing cycle.',NULL,NULL,391,3.84,TRUE),
('KB010','Provider','Network','How do I find an in-network provider?','Use our online provider directory or call member services to find in-network providers in your area.',NULL,NULL,456,3.06,TRUE),
